    83  // Plugin is an implementation of admission.Interface.
    84  type Policy = v1.ValidatingAdmissionPolicy
    85  type PolicyBinding = v1.ValidatingAdmissionPolicyBinding
    86  type PolicyEvaluator = Validator
    87  type PolicyHook = generic.PolicyHook[*Policy, *PolicyBinding, PolicyEvaluator]
