    97  func NewPlugin(_ io.Reader) *Plugin {
    98          handler := admission.NewHandler(admission.Connect, admission.Create, admission.Delete, admission.Update)
    99
   100          p := &Plugin{
   101                  Plugin: generic.NewPlugin(
   102                          handler,
   103                          func(f informers.SharedInformerFactory, client kubernetes.Interface, dynamicClient dynamic.Interface, restMapper meta.RESTMapper) generic.Source[PolicyHook] {
   104                                  return generic.NewPolicySource(
   105                                          f.Admissionregistration().V1().ValidatingAdmissionPolicies().Informer(),
   106                                          f.Admissionregistration().V1().ValidatingAdmissionPolicyBindings().Informer(),
   107                                          NewValidatingAdmissionPolicyAccessor,
   108                                          NewValidatingAdmissionPolicyBindingAccessor,
   109                                          compilePolicy,
   110                                          f,
   111                                          dynamicClient,
   112                                          restMapper,
   113                                  )
   114                          },
   115                          func(a authorizer.Authorizer, m *matching.Matcher, client kubernetes.Interface) generic.Dispatcher[PolicyHook] {
   116                                  return NewDispatcher(a, generic.NewPolicyMatcher(m))
   117                          },
   118                  ),
   119          }
   120          p.SetEnabled(true)
   121          return p
   122  }
