   124  // Validate makes an admission decision based on the request attributes.
   125  func (a *Plugin) Validate(ctx context.Context, attr admission.Attributes, o admission.ObjectInterfaces) error {
   126          return a.Plugin.Dispatch(ctx, attr, o)
   127  }
   128
   129  func compilePolicy(policy *Policy) Validator {
   130          hasParam := false
   131          if policy.Spec.ParamKind != nil {
   132                  hasParam = true
   133          }
   134          strictCost := utilfeature.DefaultFeatureGate.Enabled(features.StrictCostEnforcementForVAP)
   135          optionalVars := cel.OptionalVariableDeclarations{HasParams: hasParam, HasAuthorizer: true, StrictCost: strictCost}
   136          expressionOptionalVars := cel.OptionalVariableDeclarations{HasParams: hasParam, HasAuthorizer: false, StrictCost: strictCost}
   137          failurePolicy := policy.Spec.FailurePolicy
   138          var matcher matchconditions.Matcher = nil
   139          matchConditions := policy.Spec.MatchConditions
   140          var compositionEnvTemplate *cel.CompositionEnv
   141          if strictCost {
   142                  compositionEnvTemplate = getCompositionEnvTemplateWithStrictCost()
   143          } else {
   144                  compositionEnvTemplate = getCompositionEnvTemplateWithoutStrictCost()
   145          }
   146          filterCompiler := cel.NewCompositedCompilerFromTemplate(compositionEnvTemplate)
   147          filterCompiler.CompileAndStoreVariables(convertv1beta1Variables(policy.Spec.Variables), optionalVars, environment.StoredExpressions)
   148
   149          if len(matchConditions) > 0 {
   150                  matchExpressionAccessors := make([]cel.ExpressionAccessor, len(matchConditions))
   151                  for i := range matchConditions {
   152                          matchExpressionAccessors[i] = (*matchconditions.MatchCondition)(&matchConditions[i])
   153                  }
   154                  matcher = matchconditions.NewMatcher(filterCompiler.CompileCondition(matchExpressionAccessors, optionalVars, environment.StoredExpressions), failurePolicy, "policy", "validate", policy.Name)
   155          }
   156          res := NewValidator(
   157                  filterCompiler.CompileCondition(convertv1Validations(policy.Spec.Validations), optionalVars, environment.StoredExpressions),
   158                  matcher,
   159                  filterCompiler.CompileCondition(convertv1AuditAnnotations(policy.Spec.AuditAnnotations), optionalVars, environment.StoredExpressions),
   160                  filterCompiler.CompileCondition(convertv1MessageExpressions(policy.Spec.Validations), expressionOptionalVars, environment.StoredExpressions),
   161                  failurePolicy,
   162          )
   163
   164          return res
   165  }
   166
   167  func convertv1Validations(inputValidations []v1.Validation) []cel.ExpressionAccessor {
   168          celExpressionAccessor := make([]cel.ExpressionAccessor, len(inputValidations))
   169          for i, validation := range inputValidations {
   170                  validation := ValidationCondition{
   171                          Expression: validation.Expression,
   172                          Message:    validation.Message,
   173                          Reason:     validation.Reason,
   174                  }
   175                  celExpressionAccessor[i] = &validation
   176          }
   177          return celExpressionAccessor
   178  }
   179
   180  func convertv1MessageExpressions(inputValidations []v1.Validation) []cel.ExpressionAccessor {
   181          celExpressionAccessor := make([]cel.ExpressionAccessor, len(inputValidations))
   182          for i, validation := range inputValidations {
   183                  if validation.MessageExpression != "" {
   184                          condition := MessageExpressionCondition{
   185                                  MessageExpression: validation.MessageExpression,
   186                          }
   187                          celExpressionAccessor[i] = &condition
   188                  }
   189          }
   190          return celExpressionAccessor
   191  }
   192
   193  func convertv1AuditAnnotations(inputValidations []v1.AuditAnnotation) []cel.ExpressionAccessor {
   194          celExpressionAccessor := make([]cel.ExpressionAccessor, len(inputValidations))
   195          for i, validation := range inputValidations {
   196                  validation := AuditAnnotationCondition{
   197                          Key:             validation.Key,
   198                          ValueExpression: validation.ValueExpression,
   199                  }
   200                  celExpressionAccessor[i] = &validation
   201          }
   202          return celExpressionAccessor
   203  }
   204
   205  func convertv1beta1Variables(variables []v1.Variable) []cel.NamedExpressionAccessor {
   206          namedExpressions := make([]cel.NamedExpressionAccessor, len(variables))
   207          for i, variable := range variables {
   208                  namedExpressions[i] = &Variable{Name: variable.Name, Expression: variable.Expression}
   209          }
   210          return namedExpressions
   211  }

