   136  // ValidateInitialization - once clientset and informer factory are provided, creates and starts the admission controller
   137  func (c *Plugin[H]) ValidateInitialization() error {
   138          // By default enabled is set to false. It is up to types which embed this
   139          // struct to set it to true (if feature gate is enabled, or other conditions)
   140          if !c.enabled {
   141                  return nil
   142          }
   143          if c.Handler == nil {
   144                  return errors.New("missing handler")
   145          }
   146          if c.informerFactory == nil {
   147                  return errors.New("missing informer factory")
   148          }
   149          if c.client == nil {
   150                  return errors.New("missing kubernetes client")
   151          }
   152          if c.restMapper == nil {
   153                  return errors.New("missing rest mapper")
   154          }
   155          if c.dynamicClient == nil {
   156                  return errors.New("missing dynamic client")
   157          }
   158          if c.stopCh == nil {
   159                  return errors.New("missing stop channel")
   160          }
   161          if c.authorizer == nil {
   162                  return errors.New("missing authorizer")
   163          }
   164
   165          // Use default matcher
   166          namespaceInformer := c.informerFactory.Core().V1().Namespaces()
   167          c.matcher = matching.NewMatcher(namespaceInformer.Lister(), c.client)
   168
   169          if err := c.matcher.ValidateInitialization(); err != nil {
   170                  return err
   171          }
   172
   173          c.source = c.sourceFactory(c.informerFactory, c.client, c.dynamicClient, c.restMapper)
   174          c.dispatcher = c.dispatcherFactory(c.authorizer, c.matcher, c.client)
   175
   176          pluginContext, pluginContextCancel := context.WithCancel(context.Background())
   177          go func() {
   178                  defer pluginContextCancel()
   179                  <-c.stopCh
   180          }()
   181
   182          go func() {
   183                  err := c.source.Run(pluginContext)
   184                  if err != nil && !errors.Is(err, context.Canceled) {
   185                          utilruntime.HandleError(fmt.Errorf("policy source context unexpectedly closed: %w", err))
   186                  }
   187          }()
   188
   189          err := c.dispatcher.Start(pluginContext)
   190          if err != nil && !errors.Is(err, context.Canceled) {
   191                  utilruntime.HandleError(fmt.Errorf("policy dispatcher context unexpectedly closed: %w", err))
   192          }
   193
   194          c.SetReadyFunc(func() bool {
   195                  return namespaceInformer.Informer().HasSynced() && c.source.HasSynced()
   196          })
   197          return nil
   198  }
   199
   200  func (c *Plugin[H]) Dispatch(
   201          ctx context.Context,
   202          a admission.Attributes,
   203          o admission.ObjectInterfaces,
   204  ) (err error) {
   205          if !c.enabled {
   206                  return nil
   207          } else if c.shouldIgnoreResource(a) {
   208                  return nil
   209          } else if !c.WaitForReady() {
   210                  return admission.NewForbidden(a, fmt.Errorf("not yet ready to handle request"))
   211          }
   212
   213          return c.dispatcher.Dispatch(ctx, a, o, c.source.Hooks())
   214  }
   215
   216  func (c *Plugin[H]) shouldIgnoreResource(attr admission.Attributes) bool {
   217          gvr := attr.GetResource()
   218          // exclusion decision ignores the version.
   219          gr := gvr.GroupResource()
   220          return c.excludedResources.Has(gr)
   221  }

